var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마, 그동안 뒤에서 우리를 베껴대고 있을 줄이야……!","JPN":"まさか、裏でずっとあたしたちをコピーしていたなんて……！","ENG":"I didn't realize you were copying us behind our backs all this time...!","TWN":"沒想到，這段時間你竟然在背後模仿我們……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무대가 소란스럽군요.","JPN":"舞台が騒がしいですね。","ENG":"The stage is full of too much commotion.","TWN":"舞台真是熱鬧啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게임이 끝난 순간부터 모든 것은 예정된 전개예요.","JPN":"ゲームが終わった瞬間から、すべては予定通りの展開です。","ENG":"Everything after the Game's ending had already been planned.","TWN":"從遊戲結束的那一刻起，一切都是事先安排好的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"순순히 포기하세요. 당신은 이미 제 각본에서 벗어날 수 없습니다.","JPN":"大人しく諦めなさい。あなたはもう、私の脚本から逃げられません。","ENG":"So, give up. You cannot escape my script already.","TWN":"乖乖放棄吧，你已經無法逃出我的劇本了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"크하아아악……!!","JPN":"ぐあああ……っ！！","ENG":"Graah!!","TWN":"嗚啊啊啊……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 치명상이로군요. 복부 출혈을 멈추지 못하면 죽을 겁니다.","JPN":"致命傷ですね。腹部の出血を止めないと死にますよ。","ENG":"With this, you are fatally wounded. If you don't stop the bleeding from your abdomen, you will die.","TWN":"這下是致命傷了，如果不能止住腹部出血的話，會死的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"크, 크큭……!","JPN":"く、くく……！","ENG":"K-keke...!","TWN":"呵，呵呵……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래, 어쩐지 익숙하다 했는데…….","JPN":"ああ、どうりで既視感がすると思った……","ENG":"Yeah, it felt somehow familiar...","TWN":"是啊，難怪覺得這麼熟悉……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뭐가 그리 우습죠?","JPN":"なにがおかしいんですか？","ENG":"What's so amusing?","TWN":"有什麼好笑的？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"널 처음 봤을 때부터, 느껴졌던 이 불쾌한 느낌…….","JPN":"あんたを初めて見た瞬間から感じたこの不快感……","ENG":"This unpleasant feeling I've had since I first saw you...","TWN":"從第一次見到你開始，就覺得哪裡不對勁……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이제야 알겠어……. 지금까지 전면에 나서지 않았던 이유가 있었어…….","JPN":"やっとわかった……今まで前面に立つのをさけた理由……","ENG":"I get it now... Why you wouldn't show your face in the front lines...","TWN":"現在才明白……你一直沒有出手的原因……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너, 그 빌어먹을 <color=#ffd34c>암군</color>이랑 계약했구나?","JPN":"あんた、あのくそみたいな<color=#ffd34c>暗君</color>と契約したでしょ？","ENG":"You made a contract with that damned <color=#ffd34c>Ignorant Monarch</color>, didn't you?","TWN":"你和那個該死的<color=#ffd34c>昏君</color>簽了契約嗎！？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"의외네요. 그 힘은 아직 숨겨두고 있었는데.","JPN":"気づくとは驚きました。その力はまだ隠していたつもりなのに。","ENG":"That's surprising. I've been hiding that power from everyone.","TWN":"真意外，那股力量還一直隱藏著呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"인정하죠. 역시 리트리버답게 제법 냄새를 잘 맡는군요.","JPN":"認めます。レトリーバーだけに、匂いに敏感なのですね。","ENG":"I'll admit. You do have a sharp nose like a real retriever.","TWN":"我承認。不愧是獵犬，嗅覺還真是靈敏。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼 네 목적은 역시 관 뚜껑을 여는 건가……?","JPN":"じゃあやっぱりあんたの目的は棺を開けること……？","ENG":"Then, your goal is to open the Coffin...?","TWN":"那麼，你的目的果然是打開棺材嗎……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하지만 대체 무슨 배짱으로…….","JPN":"けど、なんの魂胆があって……","ENG":"But you'd have to be insane to–","TWN":"可是到底憑什麼……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 그걸 알아냈다고 해서 뭐가 달라질까요?","JPN":"さあ、それがわかったところで何も変わらないでしょう。","ENG":"Well, what changes with your knowing that?","TWN":"這個嘛，知道了又能有什麼不同呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아쉽지만, 그 정보가 제때 대장님께 도착하는 일은 없을 겁니다.","JPN":"残念ながら、その情報を隊長に伝えようとしたところで間に合いません。","ENG":"I'm sorry, but that information will never reach Commander's ears on time.","TWN":"可惜，這個資訊是不會被及時送到隊長手中的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 당신은 한동안 이 무대에서 퇴장하게 될 테니까.","JPN":"なぜなら、あなたにはしばらくこの舞台から退場してもらうので。","ENG":"That's because you will be off this stage for a while now.","TWN":"因為你將暫時退出這個舞台。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 순순히 당해줄 것 같아?","JPN":"ちっ、大人しくやられるわけないでしょ！","ENG":"Tch! You think I'm going down that easily?","TWN":"嘖，你以為我會乖乖認命嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"마지막의 마지막까지 깽판 쳐줄 테니까…….","JPN":"力尽きるまで大暴れしてやるから……","ENG":"I'll make sure to cause a ruckus until the very end...","TWN":"我會糾纏到最後一刻……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어디 끌어낼 수 있으면 끌어내 보라고!!","JPN":"やれるもんならやってみな！！","ENG":"so I dare you to end me if you can!!","TWN":"有本事就在這裡殺了我！！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마지막 일격을 가하는 뉘앙스를 보이면서, 발밑 지면을 노려 도망칠 틈을 만들었군요.","JPN":"最後の一撃に見せかけて、足元を狙い逃げる隙を作ろうとしましたね。","ENG":"While pretending to attempt a final blow, she aimed at the ground, creating a chance to escape.","TWN":"看似要搏命一擊，但卻瞄準腳下的地面製造了逃跑的機會。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};